rss.channel:
{{ if eq .Title .Site.Title }}{{ .Site.Title }}{{ else }}{{ with .Title }}{{.}} on {{ end }}{{ .Site.Title }}{{ end }}
{{ .Permalink }}
Recent content {{ if ne .Title .Site.Title }}{{ with .Title }}on {{.}} {{ end }}{{ end }}on {{ .Site.Title }}
Hugo -- gohugo.io
{{ .Site.LanguageCode }}
{{ if not .Date.IsZero }}
{{ .Date.Format "Mon, 02 Jan 2006 15:04:05 -0700" | safeHTML }}
{{ end }}
{{ with .OutputFormats.Get "RSS" }}

{{ end }}
{{ range .RegularPages }}


  {{ .Title }}
  {{ .Permalink }}
  {{ .Date.Format "Mon, 02 Jan 2006 15:04:05 -0700" | safeHTML }}
  {{ .Permalink }}

    {{- printf "" | safeHTML -}}
    {{- $content := .Content -}}
    {{- /* 1. Barrierefreiheits-Texte (sr-only) entfernen */ -}}
    {{- $content = $content | replaceRE "<span class=\"sr-only\">.*?</span>" "" -}}
    {{- /* 2. Heading Hashtags (##) entfernen */ -}}
    {{- $content = $content | replaceRE "<span class=\"heading-hashtag\" aria-hidden=\"true\">.*?</span>" "" -}}
    {{- /* 3. Design-Klassen (linux-egg) säubern */ -}}
    {{- $content = $content | replaceRE "<span class=\"linux-egg\">(.*?)</span>" "$1" -}}
    {{- /* 4. Whitespace aufräumen */ -}}
    {{- $content = $content | replaceRE "[\n\r]+" "\n" -}}
    {{- $content | safeHTML -}}
    {{- printf "" | safeHTML -}}


{{ end }}
